{
  "formal_minutes": {
    "회의명": "UI Theme Package Release Readiness",
    "프로젝트_코드": "PUBLIC_MEETING_SMOKE",
    "참석자": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 스모크 테스트가 통과될 경우 금요일 15:00 KST로 한다.",
        "notes": "수요일 릴리스는 최종 결정이 아니라 내부 stretch goal로만 언급되었다."
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인한다.",
        "notes": "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "status": "rejected",
        "reason": "논의 후 최종 결정에서 제외되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스",
        "status": "internal_stretch_goal_only",
        "notes": "Doyun이 스모크 테스트 선통과 필요성을 이유로 반대했다."
      }
    ],
    "non_decisions": [
      {
        "item": "README install steps를 목요일까지 검토",
        "status": "제안 또는 희망 사항",
        "notes": "가능하면 목요일까지 검토하자는 언급은 있었지만 owner가 지정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path가 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README install steps가 오래된 경우 release notes가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "release note에 내부 수요일 stretch goal을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_action"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_action"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 generated tarball path를 확인한다.",
      "due": null,
      "status": "confirmed_no_exact_deadline",
      "source_certainty": "confirmed_action_without_exact_deadline"
    },
    {
      "owner": null,
      "task": "README install steps를 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "unassigned_non_decision",
      "source_certainty": "mentioned_but_no_owner_assigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과 공유 여부를 확인한다.",
      "Doyun의 금요일 12:00 KST action_items.md triage note 작성 여부를 확인한다.",
      "스모크 결과 게시 후 Hara가 generated tarball path를 확인했는지 확인한다.",
      "README install steps 검토 owner를 지정할지 결정한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "release note에 내부 수요일 stretch goal을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "운영 장애",
      "법무 승인 요건",
      "지정되지 않은 owner",
      "명시되지 않은 deadline"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "production outage는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요건은 언급되지 않았으므로 생성하지 않는다.",
    "owners": "명시된 action item owner만 사용한다. README 검토 owner는 null로 유지한다.",
    "deadlines": "명시된 due만 사용한다. Hara 항목에는 정확한 deadline을 만들지 않는다.",
    "release_condition": "금요일 15:00 KST 공개 릴리스 목표는 smoke pass 조건부로만 기록한다."
  }
}
